sql:
SELECT AVG(effectiveness) AS average_effectiveness
FROM campaign_strategies
WHERE candidate_id = 1;

SELECT SUM(money_raised) AS total_money_raised
FROM fundraising
WHERE candidate_id = 1;

external_knowledge:
- The years 1980 and 1990 refer to the range of election years; 
- The amount of 100,000 refers to USD; 
- The 'fundraising' table contains the money raised by each candidate for the party; 
- The 'candidates' table contains information about each candidate, including the party they belong to and the year they ran for election.

sql:
SELECT total_donations, money_raised
FROM fundraising
WHERE year = 1980;

external_knowledge:
- "Successful" candidates are ranked based on their performance in the primary election, with higher vote counts and endorsement points indicating better performance; 
- The election year 1980 is assumed to be the year of interest, as specified in the query;
- The amount of $100,000 and 100 endorsement points are the thresholds for a candidate to be considered successful in terms of fundraising and endorsements, respectively.

sql:
SELECT SUM(endorsement_points) AS total_endorsement_points, MAX(endorsement_points) AS max_endorsement_points
FROM endorsements
WHERE candidate_id = (SELECT candidate_id FROM candidates WHERE name = 'George H.W. Bush');

SELECT event_type, year, COUNT(fundraising_id) AS total_events, SUM(money_raised) AS total_money_raised
FROM fundraising
GROUP BY event_type, year;

SELECT endorser_name, endorser_type
FROM endorsements
WHERE year = 1980;
